#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,C,Q; scanf("%d %d %d",&N,&C,&Q);
        for(int i=0;i<Q;i++){
            int L,R; scanf("%d %d",&L,&R);
            if(C>=L && C<=R) C = L + R - C;
        }
        printf("%d\n",C);
    }
    return 0;
}

